INSERT INTO `dishes` (`id`, `name`, `category`, `image`, `description`, `price`) VALUES
(1, 'Phở', 'nước', 'images/pho.jpg', '<p><b>1. Nguồn gốc của Phở:</b>\r\nPhở bắt nguồn từ miền Bắc Việt Nam, cụ thể là ở Hà Nội vào khoảng đầu thế kỷ 20. Mặc dù chưa có một câu chuyện chính thức xác nhận sự ra đời của phở, nhưng có nhiều giả thuyết khác nhau về nguồn gốc của món ăn này:\r\n\r\nMột giả thuyết phổ biến là phở được ảnh hưởng từ các món súp Trung Quốc, như món bánh phở của người Quảng Đông.\r\n\r\nMột giả thuyết khác cho rằng phở bắt nguồn từ món hủ tiếu của người Hoa, được người Việt cải biên lại và phát triển.\r\nMón phở nhanh chóng trở thành một phần không thể thiếu trong nền văn hóa ẩm thực Việt Nam và trở nên phổ biến tại các quán ăn, đặc biệt là ở Hà Nội và Sài Gòn.</p>\r\n<hr>\r\n<p><b>2. Các loại Phở:</b>\r\nCó hai loại phở phổ biến nhất ở Việt Nam:\r\n\r\n+ Phở Bò: Đây là loại phở phổ biến nhất, sử dụng thịt bò thái lát mỏng, nước dùng từ xương bò được ninh trong nhiều giờ. Phở bò có thể có nhiều biến thể như phở tái, phở chín, phở gầu, phở nạm.\r\n+ Phở Gà: Phở gà sử dụng thịt gà thay cho thịt bò, nước dùng được ninh từ xương gà. Phở gà có phần nước dùng nhẹ nhàng và thanh mát hơn so với phở bò.</p>\r\n<hr>\r\n<p><b>3. Nguyên liệu chính của Phở</b>\r\n+ Sợi phở: Là những sợi bánh phở làm từ gạo, có hình dạng mỏng và dài. Sợi phở mềm và dai, được chế biến từ gạo xay mịn và nấu qua nước sôi.\r\n\r\n+ Nước dùng (Broth): Nước dùng là yếu tố quan trọng nhất của món phở, thường được ninh từ xương bò hoặc xương gà, kết hợp với gia vị như hành, gừng, hồi, quế, thảo quả và muối. Nước dùng phải trong, thơm và đậm đà.\r\n\r\n+ Thịt: Phở bò thường dùng các phần thịt bò như gầu, nạm, tái hoặc bắp, và có thể ăn kèm với thịt bò viên. Phở gà thường dùng thịt gà luộc hoặc nướng.\r\n\r\n+ Rau thơm và gia vị: Phở thường được ăn kèm với các loại rau thơm như hành lá, húng quế, ngò gai, và giá đỗ. Ngoài ra, có thể thêm gia vị như chanh, ớt, tương đen, mắm tôm, và nước mắm tùy sở thích.</p>\r\n<hr>\r\n<p><b>4. Cách nấu Phở:</b>\r\nNước dùng phở là yếu tố quyết định hương vị của món ăn này. Để làm nước dùng phở, người ta sẽ ninh xương trong nhiều giờ, thường là từ 6-8 giờ để xương tiết ra hết chất ngọt và độ béo. Gia vị như hành, gừng, quế, thảo quả, hồi... được cho vào để tạo ra mùi thơm đặc trưng.\r\n\r\nChế biến thịt:\r\n+ Phở bò: Thịt bò có thể thái mỏng và cho vào tô phở, hoặc nấu chín (phở chín), hoặc để tái (phở tái). Phở bò cũng có thể ăn kèm với thịt gầu, nạm, hoặc thịt viên.\r\n+ Phở gà: Thịt gà được luộc, sau đó xé nhỏ và cho lên trên bát phở.\r\n\r\nLắp ráp phở:\r\nSau khi có nước dùng và thịt, người ta sẽ trụng sợi phở qua nước sôi cho nóng, sau đó cho vào tô. Nước dùng nóng được chan vào tô, sau đó cho thịt lên trên. Món ăn được hoàn thiện với rau thơm, gia vị, chanh, và ớt.</p>\r\n<hr>\r\n<p><b>5. Cách ăn Phở:</b>\r\nPhở thường được ăn vào buổi sáng, nhưng cũng có thể ăn vào bất kỳ thời gian nào trong ngày. Một tô phở đầy đủ sẽ bao gồm thịt, sợi phở, nước dùng và rau sống. Khi ăn, thực khách có thể thêm gia vị theo sở thích, chẳng hạn như chanh, tương ớt, hoặc mắm tôm.</p>\r\n<hr>\r\n<p><b>6. Phở trong văn hóa Việt Nam:</b>\r\nPhở không chỉ là một món ăn mà còn là một phần của nền văn hóa Việt Nam. Nó là một món ăn quen thuộc trong đời sống hàng ngày của người dân Việt Nam và trở thành món ăn đại diện cho nền ẩm thực của quốc gia này. Phở đã xuất hiện trong nhiều cuộc thi ẩm thực, chương trình truyền hình quốc tế, và đặc biệt là đã được UNESCO công nhận là món ăn mang tính di sản văn hóa.</p>\r\n\r\n\r\n', 30000),
(2, 'Bánh khọt', 'khô', 'images/banhkhot.jpeg', '<p><b>1. Nguồn gốc của Bánh Khọt</b>\r\nBánh khọt là một món ăn truyền thống của miền Nam Việt Nam, đặc biệt phổ biến ở các tỉnh miền Đông Nam Bộ như Bình Dương, Vũng Tàu, và Sài Gòn. Món bánh này có hình dáng giống như những chiếc bánh nhỏ được chiên vàng giòn và thường được ăn kèm với tôm, thịt và rau sống.\r\n\r\nNguồn gốc: Món bánh khọt có thể bắt nguồn từ những người dân miền Nam với nguyên liệu đơn giản nhưng rất hấp dẫn. Cái tên \"khọt\" xuất phát từ âm thanh của bánh khi được chiên trong chảo dầu nóng, tạo nên tiếng kêu giòn tan.</p>\r\n<hr>\r\n<p><b>2. Các loại Bánh Khọt</b>\r\nBánh khọt có nhiều biến thể tùy theo vùng miền và sở thích của người ăn. Hai loại bánh khọt phổ biến nhất là:\r\n\r\nBánh Khọt tôm: Đây là loại bánh khọt phổ biến nhất, với phần mặt bánh được phủ tôm tươi, chiên giòn và có vị ngọt tự nhiên từ tôm.\r\nBánh Khọt thịt: Một số nơi còn có biến thể bánh khọt với nhân thịt heo, thịt gà hoặc các loại nhân khác như thịt bò, nhưng loại này ít phổ biến hơn bánh khọt tôm.</p>\r\n<hr>\r\n<p><b>3. Nguyên liệu chính của Bánh Khọt</b>\r\nBánh khọt được làm từ các nguyên liệu chính như sau:\r\n\r\nBột gạo: Bột gạo là nguyên liệu chính để làm vỏ bánh. Bột này được pha loãng với nước và gia vị để tạo thành một hỗn hợp mịn, sau đó được chiên giòn trong dầu nóng.\r\nTôm: Thường dùng tôm tươi, bỏ vỏ, cắt nhỏ hoặc để nguyên con tùy theo sở thích của từng người.\r\nThịt heo (nếu có): Một số nơi có thêm nhân thịt heo băm hoặc thái lát mỏng để làm nhân bánh.\r\nGia vị và gia giảm: Món bánh này có thể được nêm gia vị như muối, tiêu, đường, nước mắm, tỏi, hành, và tiêu để tạo nên hương vị đặc trưng.\r\nRau sống: Bánh khọt thường được ăn kèm với rau sống như xà lách, rau thơm, giá đỗ, ngò rí để tạo thêm độ tươi mát và giúp cân bằng vị béo ngậy của bánh.</p>\r\n<hr>\r\n<p><b>4. Cách nấu Bánh Khọt</b>\r\nCách làm bánh khọt không quá khó, nhưng yêu cầu khéo léo để bánh được giòn và đều. Dưới đây là các bước cơ bản:\r\n\r\nChuẩn bị bột: Trộn bột gạo với nước, một chút bột nghệ để tạo màu vàng và một chút muối cho đậm đà. Hỗn hợp này phải mịn và không quá đặc.\r\nChiên bánh: Đun nóng chảo bánh khọt (chảo nhỏ có nhiều lỗ tròn) với dầu. Múc một lượng bột vừa đủ vào từng khuôn bánh, sau đó thêm tôm hoặc nhân thịt lên trên. Khi bánh đã vàng giòn, dùng một chiếc thìa gắp bánh ra.\r\nThưởng thức: Bánh khọt thường được ăn nóng kèm với rau sống và các loại gia vị như nước mắm chua ngọt, ớt, tỏi băm nhỏ.</p>\r\n<hr>\r\n<p><b>5. Cách ăn Bánh Khọt</b>\r\nBánh khọt được ăn kèm với rau sống và các gia vị, cách ăn rất đơn giản:\r\n\r\nBọc rau sống: Bánh khọt nóng giòn được bọc trong lá rau sống, rồi chấm vào nước mắm chua ngọt, thêm ớt và tỏi nếu thích cay.\r\n\r\nThưởng thức từng miếng: Món bánh này thường được ăn như một món ăn vặt hoặc ăn sáng. Mỗi miếng bánh khọt đều có vị giòn rụm của vỏ bánh, vị ngọt tự nhiên từ tôm và các gia vị đậm đà.</p>\r\n<hr>\r\n<p><b>6. Bánh Khọt trong văn hóa ẩm thực Việt Nam</b>\r\nBánh khọt không chỉ là món ăn ngon mà còn là một phần của nền văn hóa ẩm thực miền Nam. Món bánh này được yêu thích trong các buổi tiệc gia đình, các dịp lễ Tết, và đặc biệt là trong các buổi tụ tập bạn bè. Đây là một trong những món ăn thể hiện sự khéo léo và sự tinh tế trong chế biến của người dân Nam Bộ.\r\n\r\nMón ăn gắn liền với đời sống miền Nam: Từ những quán ăn đường phố đến các nhà hàng lớn, bánh khọt luôn có mặt trong thực đơn của các quán ăn tại miền Nam.\r\n\r\nBánh khọt và sự kết hợp với các món ăn khác: Bánh khọt thường được ăn cùng với các món ăn khác như bánh xèo, bánh cuốn, hay các món cuốn.</p>', 50000),
(3, 'Bánh cuốn', 'khô', 'images/banhcuon.jpg', '<p><b>1. Nguồn gốc của Bánh Cuốn</b>\r\nBánh Cuốn có nguồn gốc từ miền Bắc Việt Nam, đặc biệt là ở Hà Nội. Món ăn này đã tồn tại từ cuối thế kỷ 19, với câu chuyện về sự sáng tạo của những người thợ làm bánh gạo. \r\n\r\nTrong quá trình phát triển, Bánh Cuốn được người dân miền Bắc biến tấu để phù hợp hơn với khẩu vị của người Việt. Món ăn này nhanh chóng trở thành một phần quan trọng trong ẩm thực sáng của người Hà Nội và sau đó lan rộng ra các vùng miền khác.\r\n\r\nMột giả thuyết cho rằng Bánh Cuốn bắt nguồn từ món bánh tráng cuốn của người Trung Quốc, nhưng bánh cuốn Việt Nam có sự khác biệt về nguyên liệu và cách chế biến. Món ăn đã trở thành biểu tượng ẩm thực của Hà Nội và nhiều nơi trên cả nước.</p>\r\n<hr>\r\n<p><b>2. Các loại Bánh Cuốn</b>\r\nBánh Cuốn có một số biến thể phổ biến tùy vào vùng miền và khẩu vị:\r\n\r\n+ Bánh Cuốn Thịt Heo: Loại bánh cuốn truyền thống, có nhân thịt heo băm nhỏ, mộc nhĩ, hành phi và ăn kèm với rau sống.\r\n\r\n+ Bánh Cuốn Chay: Không sử dụng thịt, mà thay vào đó là nấm, đậu phụ, và các loại rau củ.\r\n\r\n+ Bánh Cuốn Hà Nội: Đặc trưng với lớp vỏ bánh mỏng, nhân thịt heo, mộc nhĩ, hành phi và chả lụa, ăn kèm với nước mắm pha chua ngọt.\r\n\r\n+ Bánh Cuốn Cao Bằng: Một biến thể đặc biệt từ Cao Bằng, với nhân bao gồm thịt lợn, mộc nhĩ và nấm hương, được ăn kèm với rau thơm và một chút gia vị đặc trưng. </p>\r\n<hr>\r\n<p><b>3. Nguyên liệu chính của Bánh Cuốn</b>\r\nĐể làm ra món Bánh Cuốn, cần có những nguyên liệu cơ bản sau:\r\n\r\n+ Bột gạo: Bột gạo mịn được tráng thành lớp mỏng, có độ dẻo và mềm, tạo nên vỏ bánh cuốn mỏng tang.\r\n\r\n+ Thịt heo: Thịt nạc heo thường được băm nhỏ, xào với mộc nhĩ, hành phi và gia vị.\r\n\r\n+ Mộc nhĩ: Mộc nhĩ là một loại nấm có độ giòn, giúp tăng thêm độ ngon và hấp dẫn cho nhân bánh.\r\n\r\n+ Hành phi: Hành được phi vàng thơm, cho vào nhân bánh để tạo thêm hương vị.\r\n\r\n+ Nước mắm: Nước mắm pha chua ngọt (kết hợp với chanh và đường) là phần gia vị không thể thiếu, làm tăng hương vị cho bánh cuốn.\r\n\r\n+ Các loại rau sống như rau thơm, giá đỗ, ngò gai và hành lá thường được ăn kèm, tạo thêm sự tươi mát và thơm ngon cho món ăn.</p>\r\n<hr>\r\n<p><b>4. Cách chế biến Bánh Cuốn</b>\r\nCách làm Bánh Cuốn gồm các bước cơ bản như sau:\r\n\r\n+ Làm vỏ bánh: Đầu tiên, bạn tráng bột gạo trên chảo nóng, tạo thành lớp vỏ mỏng. Sau đó, dùng đũa cuộn lại để tạo thành hình bánh cuốn.\r\n\r\n+ Làm nhân: Thịt heo được băm nhỏ, xào chung với mộc nhĩ, hành phi và gia vị, tạo thành phần nhân thơm ngon.\r\n\r\n+ Hấp bánh: Các bánh cuốn đã cuộn được hấp trong nồi cho đến khi chín mềm.\r\n\r\n+ Chuẩn bị nước mắm: Nước mắm chua ngọt được pha từ nước mắm, đường, chanh và một chút tỏi ớt để làm gia vị cho bánh cuốn.</p>\r\n<hr>\r\n<p><b>5. Cách ăn Bánh Cuốn</b>\r\nBánh Cuốn thường được ăn vào bữa sáng hoặc bữa trưa, thường đi kèm với nước mắm pha chua ngọt. Một tô bánh cuốn hoàn chỉnh gồm có bánh cuốn nóng, chả lụa, rau sống và gia vị. Khi ăn, bạn có thể cho thêm nước mắm chua ngọt, ớt tươi và hành phi lên trên để tăng hương vị. Đặc biệt, Bánh Cuốn có thể ăn kèm với chả quẩy, giúp món ăn trở nên giòn ngon hơn.</p>\r\n<hr>\r\n<p><b>6. Bánh Cuốn trong văn hóa Việt Nam</b>\r\nBánh Cuốn là món ăn đặc trưng trong ẩm thực của miền Bắc Việt Nam, và có mặt trong các bữa sáng của người dân Hà Nội. Bánh Cuốn là một phần không thể thiếu trong những món ăn được yêu thích tại các quán ăn sáng nổi tiếng của thủ đô. \r\n\r\nĐặc biệt, món ăn này còn được làm từ những nguyên liệu đơn giản, dễ tìm, nhưng lại rất bổ dưỡng và dễ ăn, là lựa chọn yêu thích của nhiều người dân Việt Nam.\r\n\r\nMón Bánh Cuốn cũng là một biểu tượng văn hóa ẩm thực, thường xuyên xuất hiện trong các chương trình ẩm thực quốc tế và được du khách quốc tế biết đến khi đến thăm Việt Nam. Phần lớn người dân Việt Nam đều có ký ức gắn liền với những buổi sáng ăn Bánh Cuốn trong những quán nhỏ ven đường, tạo nên một nét đặc trưng của ẩm thực đường phố.</p>\r\n\r\n', 50000),
(4, 'Bánh mì', 'khô', 'images/banhmi.jpg', '<p><b>1. Nguồn Gốc của Bánh Mì</b>\r\nBánh Mì có nguồn gốc từ sự giao thoa giữa ẩm thực Việt Nam và Pháp trong thời kỳ thực dân. Vào đầu thế kỷ 20, người Pháp đã mang bánh mì baguette vào Việt Nam, và người Việt đã sáng tạo ra phiên bản bánh mì phù hợp với khẩu vị của mình, tạo nên món ăn đặc trưng như ngày nay. Món Bánh Mì trở thành một phần không thể thiếu trong ẩm thực đường phố, phổ biến khắp các thành phố lớn cũng như các vùng quê.\r\n\r\nVới sự kết hợp của vỏ bánh mì giòn tan và nhân đa dạng từ thịt, rau sống, gia vị, bánh mì đã nhanh chóng trở thành món ăn yêu thích của mọi lứa tuổi và trở thành một biểu tượng ẩm thực quốc gia.\r\n<hr>\r\n<p><b>2. Các Loại Bánh Mì</b>\r\nBánh Mì có rất nhiều biến thể, tùy theo nguyên liệu và cách chế biến tại từng vùng miền:\r\n\r\n+ Bánh Mì Thịt Nướng: Loại bánh mì phổ biến nhất với nhân thịt heo hoặc bò nướng thơm ngon, ăn kèm với rau sống, gia vị, và nước sốt.\r\n+ Bánh Mì Xíu Mại: Bánh mì với nhân thịt viên (xíu mại) nấu cùng nước sốt thơm ngon.\r\n+ Bánh Mì Chả Cá: Chả cá chiên hoặc nướng ăn kèm với rau thơm và gia vị.\r\nBánh Mì Chay: Phiên bản không thịt, thay bằng các nguyên liệu như đậu hũ, rau củ nướng hoặc xào, nấm.\r\n+ Bánh Mì Ốp La: Nhân bánh mì gồm trứng ốp la, ăn kèm với rau sống và gia vị.\r\n+ Bánh Mì Sài Gòn: Một biến thể nổi tiếng ở TP.HCM, với các loại nhân thịt nướng, pate, và các loại rau ăn kèm đa dạng.</p>\r\n<hr>\r\n<p>3. Nguyên Liệu Chính của Bánh Mì\r\n<br>Để làm bánh mì, các nguyên liệu cơ bản bao gồm:\r\n\r\n+ Bánh mì baguette: Bánh mì dài, vỏ giòn và ruột mềm, là phần nền tảng của món ăn.\r\n\r\n+ Thịt: Có thể là thịt nướng, thịt quay, thịt heo xào, xíu mại, chả lụa, hay các loại thịt khác.\r\n\r\n+ Pate: Là thành phần không thể thiếu trong bánh mì truyền thống, giúp tạo thêm độ béo và hương vị đặc trưng.\r\n\r\n+ Rau sống: Rau thơm, dưa leo, ngò rí, hành lá, ớt và củ cải ngâm, làm món ăn thêm tươi mát.\r\n\r\n+ Gia vị: Đường, muối, tiêu, nước tương, tương ớt, và các loại gia vị khác tạo nên hương vị đặc biệt cho bánh mì.\r\n\r\n+ Nước sốt: Một số loại bánh mì như Bánh Mì Thịt Nướng sẽ có thêm nước sốt như tương ớt hoặc nước mắm chua ngọt.</p>\r\n<hr>\r\n<p><b>4. Cách Chế Biến Bánh Mì</b>\r\nCách làm Bánh Mì bao gồm các bước cơ bản sau:\r\n\r\n+ Nướng bánh mì: Bánh mì được nướng giòn trong lò, đảm bảo lớp vỏ bánh giòn và phần ruột mềm.\r\n\r\n+ Chuẩn bị nhân: Tùy loại bánh mì, bạn sẽ làm nhân bằng cách nướng thịt, chiên trứng, hoặc xào các nguyên liệu khác như thịt heo, bò, pate, hoặc làm xíu mại.\r\n\r\n+ Sắp xếp bánh mì: Cắt bánh mì baguette làm đôi, cho các nguyên liệu vào trong, bao gồm nhân thịt, rau sống, gia vị và các loại nước sốt.\r\n\r\n+ Phục vụ: Bánh mì sẽ được ăn ngay sau khi chế biến, với lớp vỏ giòn và nhân nóng hổi.</p>\r\n<hr>\r\n<p><b>5. Cách Ăn Bánh Mì</b>\r\nBánh Mì thường được ăn như một món ăn sáng, trưa, hoặc ăn vặt vào bất kỳ thời gian nào trong ngày. Bánh mì có thể được thưởng thức trực tiếp hoặc ăn kèm với nước mắm, tương ớt, hoặc các loại gia vị khác để tăng hương vị.\r\n\r\nTùy chọn gia vị: Có thể thêm nước sốt tương ớt, tỏi ớt, hoặc các loại gia vị khác vào để món ăn thêm đậm đà.\r\n\r\nBánh Mì Kèm Chả Quẩy: Một số quán bánh mì tại Việt Nam còn phục vụ bánh mì kèm chả quẩy giòn để món ăn trở nên hoàn hảo hơn.</p>\r\n<hr>\r\n<p>6. Bánh Mì trong Văn Hóa Việt Nam\r\nBánh Mì là một món ăn gắn liền với ẩm thực đường phố Việt Nam, đặc biệt là tại các thành phố lớn như Hà Nội, TP.HCM và các tỉnh thành khác. Món ăn này không chỉ phổ biến trong các quán vỉa hè mà còn được ưa chuộng trong các nhà hàng, khách sạn, và được du khách quốc tế yêu thích khi đến thăm Việt Nam.\r\n\r\nBánh Mì cũng mang trong mình một câu chuyện lịch sử thú vị về sự kết hợp văn hóa giữa Việt Nam và Pháp, đồng thời phản ánh sự sáng tạo không ngừng của người Việt trong việc làm phong phú món ăn truyền thống. Món ăn này ngày càng được công nhận và nổi bật trên bản đồ ẩm thực quốc tế, trở thành một món ăn đặc trưng của Việt Nam mà bất cứ ai đến Việt Nam đều muốn thử.</p>', 20000),
(5, 'Cơm tấm', 'khô', 'images/comtam.jpg', '<p><b>1. Nguồn Gốc của Cơm Tấm</b>\r\nCơm Tấm là một món ăn đặc trưng của ẩm thực miền Nam Việt Nam, đặc biệt phổ biến tại TP.HCM. Cái tên \"cơm tấm\" (cơm vỡ) xuất phát từ việc món cơm này được chế biến từ loại gạo tấm — loại gạo bị vỡ trong quá trình xay xát, không được sử dụng trong các món ăn chính thống. Trái ngược với các loại cơm thường, cơm tấm có hạt gạo nhỏ và xốp hơn.\r\n\r\nMón ăn này ra đời từ lâu và có lịch sử gắn liền với đời sống của người dân lao động, được chế biến từ nguyên liệu đơn giản nhưng lại mang lại hương vị thơm ngon. Qua thời gian, cơm tấm đã phát triển thành món ăn nổi tiếng và trở thành đặc sản không thể thiếu ở TP.HCM và các vùng lân cận.</p>\r\n<hr>\r\n<p><b>2. Các Loại Cơm Tấm</b>\r\nCơm Tấm có nhiều biến thể tùy theo loại thịt và các nguyên liệu đi kèm:\r\n\r\n+ Cơm Tấm Sườn Nướng: Loại cơm tấm truyền thống, với sườn heo nướng thơm lừng, được ướp gia vị đậm đà, ăn kèm với cơm tấm và rau sống.\r\n+ Cơm Tấm Sườn, Bì, Chả: Một phần cơm tấm đặc trưng với ba loại nhân gồm sườn nướng, bì (da heo thái nhỏ, trộn thính gạo) và chả (chả lụa hoặc chả trứng).\r\n+ Cơm Tấm Gà Nướng: Cơm tấm ăn kèm với gà nướng, cũng được ướp gia vị và nướng thơm ngon.\r\n+ Cơm Tấm Bì: Dành cho những ai không thích thịt nướng, chỉ có bì (da heo trộn thính gạo) ăn kèm với cơm tấm và gia vị.\r\n+ Cơm Tấm Chả Trứng: Một biến thể phổ biến với chả trứng được làm từ thịt xay và trứng, có thể ăn kèm với cơm tấm.</p>\r\n<hr>\r\n<p><b>3. Nguyên Liệu Chính của Cơm Tấm</b>\r\nĐể làm món Cơm Tấm, cần có các nguyên liệu cơ bản sau:\r\n\r\n+ Cơm Tấm (gạo tấm): Loại gạo bị vỡ trong quá trình xay xát, hạt nhỏ, xốp và mềm khi nấu, tạo nên một nền tảng cho món ăn.\r\n+ Sườn Nướng: Sườn heo được ướp gia vị, nướng trên lửa than để có màu sắc hấp dẫn và hương vị đậm đà.\r\n+ Bì (da heo): Da heo thái nhỏ, trộn với thính gạo và gia vị, tạo nên món bì đặc trưng của cơm tấm.\r\n+ Chả (chả lụa hoặc chả trứng): Chả lụa thường được làm từ thịt nạc xay nhuyễn, trong khi chả trứng có thêm trứng và các gia vị khác để tạo độ béo và thơm.\r\n+ Nước Mắm: Là gia vị quan trọng trong cơm tấm, nước mắm chua ngọt pha từ nước mắm, đường, chanh, tỏi ớt giúp món ăn thêm phần đậm đà.\r\nRau Sống: Rau thơm, dưa leo, và các loại rau sống khác được ăn kèm, tạo sự tươi mát cho món ăn.</p>\r\n<hr>\r\n<p><b>4. Cách Chế Biến Cơm Tấm</b>\r\nCách làm Cơm Tấm gồm các bước cơ bản sau:\r\n\r\n+ Nấu cơm tấm: Gạo tấm được vo sạch và nấu bằng nồi cơm điện hoặc hấp, giúp cơm tấm trở nên xốp và mềm.\r\n+ Sườn nướng: Sườn heo được ướp với gia vị như đường, tỏi, ớt, dầu hào và các gia vị khác, sau đó nướng trên bếp than hoặc lò nướng cho đến khi chín vàng.\r\n+ Chuẩn bị bì: Da heo được thái mỏng, trộn với thính gạo và gia vị để tạo ra món bì thơm ngon.\r\n+ Chế biến chả: Chả lụa hoặc chả trứng được làm từ thịt xay nhuyễn, thêm gia vị và hấp hoặc chiên chín.\r\nNước mắm pha: Nước mắm pha chua ngọt từ nước mắm, đường, tỏi, chanh và ớt để ăn kèm với cơm tấm, tạo thêm hương vị đặc trưng.</p>\r\n<hr>\r\n<p><b>5. Cách Ăn Cơm Tấm</b>\r\nCơm Tấm thường được ăn vào bữa trưa hoặc tối, nhưng cũng có thể là bữa sáng cho những người thích món ăn này. Một phần cơm tấm hoàn chỉnh gồm có cơm tấm nóng, sườn nướng, bì, chả, và rau sống.\r\n\r\nTùy chọn gia vị: Bạn có thể cho thêm nước mắm pha, ớt tươi, tỏi hoặc hành phi lên trên để món ăn thêm đậm đà.\r\nKèm thêm đồ ăn phụ: Cơm Tấm còn có thể ăn kèm với trứng ốp la, chả quẩy hoặc dưa chua, tùy theo sở thích của từng người.</p>\r\n<hr>\r\n<p><b>6. Cơm Tấm trong Văn Hóa Việt Nam</b>\r\nCơm Tấm là một trong những món ăn phổ biến nhất tại TP.HCM và các vùng miền Nam Việt Nam. Nó không chỉ là món ăn đơn giản, ngon miệng mà còn mang đậm nét văn hóa của người dân miền Nam.\r\n\r\nMón cơm tấm cũng đã vượt ra ngoài biên giới Việt Nam, được nhiều du khách quốc tế yêu thích khi đến thăm đất nước. Cơm Tấm trở thành món ăn đường phố đặc trưng, có mặt ở hầu hết các quán ăn, từ những quán nhỏ ven đường cho đến các nhà hàng lớn, giúp người Việt Nam cũng như du khách có thể thưởng thức hương vị thơm ngon của món ăn này vào bất kỳ lúc nào trong ngày.\r\n\r\nMón ăn này không chỉ nổi bật với sự phong phú của nguyên liệu mà còn với cách chế biến đơn giản nhưng đầy sáng tạo, tạo nên một nét đặc trưng không thể nhầm lẫn trong văn hóa ẩm thực của người Việt Nam.</p>\r\n\r\n', 30000),
(6, 'Gỏi cuốn', 'khô', 'images/goicuon.jpg', '<p><b>1. Nguồn Gốc của Gỏi Cuốn</b>\r\nGỏi Cuốn hay còn gọi là \"Chả Giò Cuốn\" hay \"Spring Roll\" trong tiếng Anh, là món ăn nổi tiếng trong ẩm thực Việt Nam, đặc biệt phổ biến ở miền Nam. Mặc dù có nguồn gốc từ miền Nam, nhưng gỏi cuốn đã trở thành món ăn được yêu thích và xuất hiện khắp các vùng miền trên toàn quốc.\r\n\r\nGỏi Cuốn có nguồn gốc từ sự sáng tạo trong việc kết hợp các nguyên liệu tươi sống như rau, thịt, và bún vào trong một lớp bánh tráng mỏng, dễ ăn và đầy đủ dưỡng chất. Món ăn này không chỉ hấp dẫn vì sự tươi ngon, mà còn nhờ vào sự đa dạng trong các nguyên liệu và cách ăn kèm với nước chấm đậm đà.\r\n<hr>\r\n<p><b>2. Các Loại Gỏi Cuốn</b>\r\nGỏi Cuốn có nhiều biến thể tùy vào vùng miền và các nguyên liệu sử dụng. Một số loại gỏi cuốn phổ biến bao gồm:\r\n\r\n+ Gỏi Cuốn Tôm Thịt: Loại gỏi cuốn truyền thống với nhân tôm luộc, thịt heo luộc, rau sống và bún. Món ăn này thường được ăn kèm với nước mắm pha chua ngọt.\r\n+ Gỏi Cuốn Chay: Dành cho những người ăn chay, với nhân bao gồm rau sống, đậu hũ, nấm, và các loại rau củ tươi.\r\n+ Gỏi Cuốn Bò: Thay vì thịt heo, có thể sử dụng thịt bò xào hoặc bò tái để làm nhân cho gỏi cuốn.\r\n+ Gỏi Cuốn Cá: Một biến thể độc đáo với nhân là cá hấp hoặc cá chiên, ăn kèm với rau sống và bún.\r\n+ Gỏi Cuốn Sò Điệp: Phiên bản đặc biệt từ vùng biển với nhân sò điệp, tôm, và rau thơm.</p>\r\n<hr>\r\n<p><b>3. Nguyên Liệu Chính của Gỏi Cuốn</b>\r\nĐể làm món Gỏi Cuốn, các nguyên liệu cơ bản gồm:\r\n\r\n+ Bánh Tráng: Làm từ bột gạo, mỏng và dẻo, dùng để cuốn các nguyên liệu lại với nhau.\r\n+ Tôm: Tôm luộc hoặc hấp được dùng làm nhân chính trong gỏi cuốn, cung cấp vị ngọt tự nhiên.\r\n+ Thịt Heo: Thịt heo luộc, thái mỏng, là thành phần quen thuộc trong món gỏi cuốn.\r\n+ Bún: Sợi bún tươi mềm, giúp món ăn trở nên nhẹ nhàng và dễ ăn hơn.\r\n+ Rau Sống: Các loại rau sống như rau diếp, húng quế, ngò rí, giá đỗ, và dưa leo làm tăng thêm sự tươi mát cho món ăn.\r\n+ Đậu Hũ: Đậu hũ có thể được dùng trong các phiên bản gỏi cuốn chay, thay thế cho thịt hoặc tôm.\r\n+ Gia Vị: Gia vị đi kèm bao gồm tỏi, ớt, nước mắm, chanh, đường, và tương ớt.</p>\r\n<hr>\r\n<p><b>4. Cách Chế Biến Gỏi Cuốn</b>\r\nCách làm Gỏi Cuốn đơn giản gồm các bước cơ bản sau:\r\n\r\n+ Chuẩn bị nguyên liệu: Tôm luộc chín, thịt heo luộc thái mỏng, rau sống rửa sạch và bún trụng qua nước nóng cho mềm.\r\n+ Ngâm bánh tráng: Bánh tráng được ngâm vào nước ấm trong vài giây cho mềm ra.\r\n+ Cuốn gỏi: Đặt bánh tráng lên mặt phẳng, cho vào giữa các nguyên liệu như tôm, thịt, rau sống và bún, sau đó cuốn chặt lại.\r\n+ Cắt và bày trí: Cắt gỏi cuốn thành từng miếng vừa ăn và bày ra đĩa.</p>\r\n<hr>\r\n<p><b>5. Cách Ăn Gỏi Cuốn</b>\r\nGỏi Cuốn thường được ăn kèm với nước mắm pha chua ngọt hoặc tương ớt. Để thưởng thức, bạn chỉ cần nhúng từng miếng gỏi cuốn vào nước chấm và thưởng thức.\r\n\r\nTùy chọn gia vị: Ngoài nước mắm chua ngọt, một số người thích cho thêm ớt, tỏi, hoặc giấm vào nước chấm để tăng hương vị.\r\n\r\nKèm các món ăn khác: Gỏi cuốn thường được ăn kèm với các món khác như bún, chả giò, hoặc dùng như một món khai vị nhẹ nhàng cho bữa ăn.</p>\r\n<hr>\r\n<p><b>6. Gỏi Cuốn trong Văn Hóa Việt Nam</b>\r\nGỏi Cuốn là món ăn đặc trưng của ẩm thực miền Nam, thường được ăn trong các bữa tiệc gia đình, trong các buổi gặp mặt bạn bè, hoặc như một món ăn vặt yêu thích. Gỏi cuốn không chỉ phổ biến ở Việt Nam mà còn được yêu thích trên toàn thế giới, đặc biệt tại các nhà hàng châu Á ở các quốc gia phương Tây.\r\n\r\nVới sự kết hợp hài hòa giữa các nguyên liệu tươi sống và gia vị đơn giản, gỏi cuốn đã trở thành món ăn đường phố rất phổ biến, mang đến một trải nghiệm ẩm thực dễ chịu, ngon miệng và bổ dưỡng. Món ăn này cũng dễ dàng được biến tấu tùy theo khẩu vị và sở thích của mỗi người, từ món gỏi cuốn tôm thịt đến các phiên bản chay hoặc hải sản.</p>', 15000),
(7, 'Hủ tiếu', 'nước', 'images/hutieu.jpg', '<p><b>1. Nguồn Gốc của Hủ Tiếu</b>\r\nHủ Tiếu là một món ăn đặc trưng trong ẩm thực miền Nam Việt Nam, với nguồn gốc có thể bắt nguồn từ Trung Quốc. Tuy nhiên, qua quá trình giao thoa văn hóa và sáng tạo của người Việt, hủ tiếu đã trở thành một món ăn đặc sắc mang đậm hương vị Việt. Món ăn này được du nhập vào Nam Bộ từ thời gian khá lâu, từ những người Hoa sống ở miền Nam.\r\n\r\nTheo thời gian, hủ tiếu đã có nhiều biến thể và trở thành một phần không thể thiếu trong ẩm thực đường phố của người dân TP.HCM và các tỉnh miền Nam. Hủ tiếu có thể được ăn theo nhiều cách khác nhau, với nước dùng trong, ngọt thanh, kèm theo những loại thịt khác nhau như tôm, sườn, thịt bò, hoặc gà.</p>\r\n<hr>\r\n<p><b>2. Các Loại Hủ Tiếu</b>\r\nHủ Tiếu có rất nhiều biến thể tùy theo vùng miền và cách chế biến. Các loại hủ tiếu phổ biến bao gồm:\r\n\r\n+ Hủ Tiếu Nam Vang: Là loại hủ tiếu nổi tiếng nhất, với nước dùng trong, ngọt, ăn kèm với tôm, thịt heo, gan, và chả lụa. Món ăn này thường được rắc thêm hành phi và rau sống.\r\n+ Hủ Tiếu Mỹ Tho: Món hủ tiếu này có đặc trưng là sợi hủ tiếu dai, nước dùng ngọt và ăn kèm với thịt nạm, tôm, mực, cùng rau thơm.\r\n+ Hủ Tiếu Sa Đéc: Nổi bật với cách chế biến đơn giản, nước dùng ngọt từ xương heo và ăn kèm với thịt heo, tôm, rau sống và các gia vị đặc trưng.\r\n+ Hủ Tiếu Sườn: Đây là biến thể của hủ tiếu Nam Vang nhưng thay vì các loại thịt khác, món ăn này sử dụng sườn heo nướng hoặc hầm, tạo thêm độ ngọt và béo cho nước dùng.\r\n+ Hủ Tiếu Chay: Phiên bản không có thịt, chỉ có rau củ, đậu hũ và nấm, thích hợp cho người ăn chay hoặc tìm kiếm món ăn nhẹ nhàng, bổ dưỡng.</p>\r\n<hr>\r\n<p><b>3. Nguyên Liệu Chính của Hủ Tiếu</b>\r\nĐể làm một tô hủ tiếu, bạn cần có các nguyên liệu cơ bản sau:\r\n\r\n+ Sợi Hủ Tiếu: Sợi hủ tiếu có thể làm từ bột gạo hoặc bột mì, có thể là sợi nhỏ hoặc sợi lớn, mềm hoặc dai tùy theo loại hủ tiếu.\r\n+ Nước Dùng: Nước dùng trong hủ tiếu thường được ninh từ xương heo, xương gà hoặc xương bò. Nước dùng có vị ngọt thanh tự nhiên, giúp món ăn thêm đậm đà.\r\n+ Tôm: Tôm luộc hoặc hấp được sử dụng làm nguyên liệu chính trong các loại hủ tiếu hải sản.\r\n+ Thịt Heo: Thịt heo có thể là thịt nạc hoặc ba rọi, thường được hầm hoặc xào trước khi cho vào tô hủ tiếu.\r\n+ Chả Lụa: Chả lụa cắt lát mỏng, là một thành phần không thể thiếu trong hủ tiếu.\r\n+ Gan Heo: Gan heo được thái mỏng và thường được ăn kèm trong các loại hủ tiếu Nam Vang.\r\n+ Rau Sống: Rau sống như giá đỗ, ngò gai, hành lá, rau diếp, húng quế... tạo sự tươi mát cho món ăn.\r\n+ Gia Vị: Bao gồm nước mắm, đường, tiêu, tỏi, ớt và hành phi để tăng thêm hương vị cho tô hủ tiếu.</p>\r\n<hr>\r\n<p><b>4. Cách Chế Biến Hủ Tiếu</b>\r\nCách làm Hủ Tiếu bao gồm các bước cơ bản sau:\r\n\r\n+ Nấu nước dùng: Xương heo hoặc xương gà được ninh lâu với các gia vị như hành, tỏi, gừng, để tạo ra nước dùng ngọt thanh, trong veo.\r\n+ Chuẩn bị nguyên liệu: Thịt heo, tôm, gan, chả lụa được chế biến theo cách phù hợp: tôm luộc, thịt heo thái mỏng, chả lụa cắt lát mỏng. Nếu là hủ tiếu sườn, sườn sẽ được hầm mềm hoặc nướng.\r\n+ Luộc hoặc trụng hủ tiếu: Sợi hủ tiếu được luộc hoặc trụng qua nước sôi để sợi mềm và dai vừa phải.\r\n+ Bày trí tô hủ tiếu: Cho hủ tiếu đã luộc vào tô, thêm thịt, tôm, chả lụa, gan và rau sống vào. Sau đó, đổ nước dùng nóng lên trên.\r\n+ Thêm gia vị: Khi ăn, bạn có thể thêm gia vị như tỏi, ớt, hành phi, tiêu và nước mắm chua ngọt để món ăn thêm đậm đà.</p>\r\n<hr>\r\n<p><b>5. Cách Ăn Hủ Tiếu</b>\r\nHủ Tiếu thường được ăn vào bữa sáng hoặc bữa trưa, có thể ăn nóng hoặc ăn với các loại gia vị tùy theo khẩu vị của từng người.\r\n\r\nGia vị tùy chọn: Bạn có thể thêm ớt, tiêu, nước mắm pha chua ngọt, hành phi, hoặc tương ớt để tăng thêm hương vị cho món hủ tiếu.\r\n\r\nKèm rau sống: Gỏi cuốn rau sống như giá đỗ, rau thơm, hành lá, ngò gai giúp làm tăng thêm sự tươi mát cho món ăn.\r\n\r\nSử dụng chanh: Một số người còn cho thêm vài lát chanh vào tô hủ tiếu để tạo vị chua nhẹ, giúp cân bằng vị ngọt của nước dùng.</p>\r\n<hr>\r\n<p><b>6. Hủ Tiếu trong Văn Hóa Việt Nam</b>\r\nHủ Tiếu là một món ăn phổ biến trong ẩm thực miền Nam, đặc biệt là tại TP.HCM và các tỉnh đồng bằng sông Cửu Long. Đây là một trong những món ăn sáng rất được yêu thích, được người dân tiêu thụ hằng ngày. Món ăn này cũng có mặt tại các quán ăn, nhà hàng, và là món ăn đường phố quen thuộc.\r\n\r\nVới hương vị thanh nhẹ, dễ ăn, hủ tiếu không chỉ là món ăn dân dã, mà còn được xem là một phần của nét văn hóa ẩm thực Việt Nam. Món ăn này còn được nhiều du khách quốc tế yêu thích khi đến thăm Việt Nam, và đã trở thành một món ăn đại diện cho sự giao thoa ẩm thực giữa Việt Nam và các nước Đông Nam Á.</p>', 50000),
(8, 'Bún bò Huế', 'nước', 'images/bunbohue.jpg', '<p><b>1. Nguồn Gốc của Bún Bò Huế</b>\r\nBún Bò Huế là một món ăn nổi tiếng của Huế, nằm ở miền Trung Việt Nam. Món ăn này ra đời từ những năm 1950 tại Huế, với đặc trưng là nước dùng đậm đà, thơm mùi mắm ruốc, và hương vị cay nồng. Ban đầu, bún bò Huế được chế biến cho giới thượng lưu của cung đình Huế, nhưng dần dần trở thành món ăn phổ biến, được yêu thích trên khắp cả nước. Nước dùng của bún bò Huế là sự kết hợp hoàn hảo của mắm ruốc, sả, ớt, tỏi, mang đến hương vị đặc trưng khó nhầm lẫn.</p>\r\n<hr>\r\n<p><b>2. Các Loại Bún Bò Huế</b>\r\n+ Bún Bò Huế truyền thống: Là món bún bò cơ bản, bao gồm nước dùng đậm đà, ăn kèm với thịt bò, giò heo, huyết và rau sống.\r\n+ Bún Bò Huế chay: Phiên bản không có thịt bò, thay vào đó là các loại rau củ, nấm và đậu hũ, phù hợp với người ăn chay nhưng vẫn giữ được hương vị đặc trưng.\r\n+ Bún Bò Huế sườn non: Một biến thể của bún bò Huế truyền thống, sử dụng sườn non thay vì giò heo, mang lại vị béo ngậy và ngọt thanh cho nước dùng.\r\n+ Bún Bò Huế hải sản: Thay vì thịt bò, giò heo, món này sử dụng tôm, cá, mực và các loại hải sản khác, mang đến hương vị nhẹ nhàng và thanh mát.</p>\r\n<hr>\r\n<p><b>3. Nguyên Liệu Chính của Bún Bò Huế</b>\r\n+ Sợi Bún: Sợi bún trong Bún Bò Huế thường là bún sợi to, dai và có màu trắng sáng. Bún được trụng qua nước sôi để mềm và dai vừa phải.\r\n+ Nước Dùng: Nước dùng của bún bò Huế được ninh từ xương bò và mắm ruốc, kết hợp với các gia vị như sả, hành, tỏi, ớt để tạo ra hương vị đậm đà và cay nồng đặc trưng.\r\n+ Thịt Bò: Thịt bò trong bún bò Huế thường là bắp bò hoặc bò tái, được thái lát mỏng hoặc làm bò viên, nấu cùng với nước dùng.\r\n+ Giò Heo: Giò heo được hầm mềm, có độ béo ngậy, tạo thêm sự đậm đà cho nước dùng.\r\n+ Huyết Heo: Huyết heo được thái lát mỏng, ăn kèm với bún bò Huế để tạo độ bùi và lạ miệng.\r\n+ Gia Vị: Các gia vị bao gồm mắm ruốc, sả, ớt, hành phi, tỏi, tiêu và rau sống như giá đỗ, ngò gai, rau húng quế, làm tăng độ thơm ngon cho món ăn.</p>\r\n<hr>\r\n<p><b>4. Cách Chế Biến Bún Bò Huế</b>\r\n+ Nấu nước dùng: Xương bò được ninh lâu với các gia vị như mắm ruốc, sả, hành, tỏi để tạo ra nước dùng ngọt thanh, trong veo và đậm đà.\r\n+ Chuẩn bị nguyên liệu: Thịt bò được thái lát mỏng, giò heo được hầm mềm, huyết được thái lát. Sau khi nước dùng đã hoàn thành, các nguyên liệu này được cho vào tô bún.\r\n+ Chuẩn bị bún: Sợi bún được luộc chín và cho vào tô, sau đó đổ nước dùng nóng lên trên.\r\n+ Bày trí tô bún: Cho các nguyên liệu vào tô bún rồi rắc thêm hành phi, ngò gai và các loại gia vị như ớt, tiêu, mắm chua ngọt để làm tăng hương vị.</p>\r\n<hr>\r\n<p><b>5. Cách Ăn Bún Bò Huế</b>\r\nGia vị tùy chọn: Bạn có thể thêm ớt, tiêu, nước mắm pha chua ngọt, hành phi, hoặc tương ớt để tăng thêm hương vị cho món ăn.\r\n\r\nKèm rau sống: Thường ăn kèm với rau sống như giá đỗ, ngò gai, hành lá, húng quế để làm tăng độ tươi mát và cân bằng vị cay của món ăn.\r\n\r\nChanh: Một số người thích thêm vài lát chanh vào tô bún để tạo vị chua nhẹ, giúp làm dịu độ cay của nước dùng.</p>\r\n<hr>\r\n<p><b>6. Bún Bò Huế trong Văn Hóa Việt Nam</b>\r\nBún Bò Huế là món ăn đặc trưng của miền Trung, đặc biệt phổ biến ở Huế, nhưng cũng được yêu thích rộng rãi ở các tỉnh thành khác. Đây là món ăn không thể thiếu trong các bữa sáng của người dân Huế, và trở thành một phần của nền ẩm thực miền Trung. \r\n\r\nVới hương vị đặc trưng, bún bò Huế không chỉ là món ăn dân dã mà còn được biết đến như một đặc sản nổi tiếng, thu hút rất nhiều du khách trong và ngoài nước. Món ăn này còn phản ánh sự sáng tạo và giao thoa văn hóa ẩm thực của các dân tộc miền Trung Việt Nam.</p>', 40000),
(9, 'Mì Quảng', 'nước', 'images/miquang.jpg', '<p><b>1. Nguồn Gốc của Mì Quảng</b>\r\nMì Quảng là món ăn đặc trưng của ẩm thực miền Trung Việt Nam, đặc biệt phổ biến tại Quảng Nam, Đà Nẵng và các tỉnh miền Trung khác. Món ăn này được cho là có nguồn gốc từ các làng quê ven sông Thu Bồn, Quảng Nam. Mì Quảng ban đầu được làm từ nguyên liệu đơn giản như mì gạo, thịt heo, tôm và rau, được chế biến và ăn kèm với nước dùng đậm đà.\r\n\r\nTrong suốt quá trình phát triển, mì Quảng đã được biến tấu với nhiều nguyên liệu khác nhau tùy theo khẩu vị và vùng miền, nhưng vẫn giữ được bản sắc và hương vị đặc trưng.</p>\r\n<hr>\r\n<p><b>2. Các Loại Mì Quảng</b>\r\nMì Quảng có rất nhiều biến thể tùy thuộc vào nguyên liệu và cách chế biến. Một số loại mì Quảng phổ biến bao gồm:\r\n\r\n+ Mì Quảng Tôm - Thịt Heo: Là loại mì Quảng phổ biến nhất, với tôm tươi, thịt heo, ăn kèm với rau sống và các gia vị đặc trưng.\r\n+ Mì Quảng Gà: Mì Quảng với thịt gà thay cho thịt heo, được nhiều người yêu thích vì hương vị thanh nhẹ và thơm ngon.\r\nMì Quảng Cá Lóc: Sử dụng cá lóc (cá rô đồng) làm nguyên liệu chính, tạo nên hương vị rất đặc biệt và hấp dẫn.\r\n+ Mì Quảng Chay: Phiên bản không có thịt, thay vào đó là các loại rau củ tươi và nấm, rất phù hợp cho người ăn chay.\r\n+ Mì Quảng Sườn Non: Thay vì sử dụng thịt heo, món mì này được chế biến từ sườn non, mang lại hương vị béo ngậy và thơm ngon.</p>\r\n<hr>\r\n<p><b>3. Nguyên Liệu Chính của Mì Quảng</b>\r\nĐể làm một tô mì Quảng thơm ngon, bạn cần chuẩn bị các nguyên liệu cơ bản sau:\r\n\r\n+ Mì Quảng: Mì Quảng thường làm từ bột gạo, sợi mì có độ dai và dày hơn so với các loại mì khác.\r\n+ Thịt Heo: Thịt heo có thể là thịt ba chỉ, thịt nạc hoặc thịt heo quay, được xào hoặc nấu chín trước khi cho vào mì.\r\n+ Tôm: Tôm tươi được chế biến cùng với các nguyên liệu khác để tạo độ ngọt cho món ăn.\r\n+ Gà: Thịt gà (thường là gà ta) được xé nhỏ hoặc để nguyên phần đùi gà, tùy vào từng loại mì.\r\n+ Rau Sống: Rau sống ăn kèm như giá đỗ, húng quế, ngò gai, hành lá, giúp tạo sự tươi mát cho món ăn.\r\n+ Gia Vị: Bao gồm hành phi, tỏi, tiêu, ớt, và đặc biệt là đậu phộng rang giã nhỏ để rắc lên mì, tạo vị bùi và hấp dẫn.\r\n+ Nước Dùng: Nước dùng của mì Quảng thường được ninh từ xương heo hoặc xương gà, nêm nếm gia vị cho ngọt thanh và đậm đà.</p>\r\n<hr>\r\n<p><b>4. Cách Chế Biến Mì Quảng</b>\r\nMì Quảng có cách chế biến khá đơn giản nhưng đầy tinh tế. Các bước cơ bản bao gồm:\r\n\r\n+ Nấu nước dùng: Ninh xương heo hoặc gà để tạo nước dùng ngọt thanh. Gia vị như hành, tỏi, tiêu được cho vào để tạo hương thơm.\r\n+ Chuẩn bị nguyên liệu: Thịt heo, tôm hoặc gà được chế biến và cắt thành miếng vừa ăn. Các loại rau sống được rửa sạch và để ráo nước.\r\n+ Nấu mì: Sợi mì Quảng được luộc chín mềm, sau đó cho vào tô.\r\n+ Trình bày: Đặt mì vào tô, cho thịt, tôm hoặc gà lên trên, rắc hành phi, đậu phộng rang, ớt tươi và rau sống lên phía trên. Sau đó, chan nước dùng nóng vào tô mì và thưởng thức.</p>\r\n<hr>\r\n<p><b>5. Cách Ăn Mì Quảng</b>\r\nMì Quảng thường được ăn vào bữa sáng hoặc bữa trưa, đặc biệt là trong các bữa tiệc gia đình hoặc dịp lễ Tết. Cách ăn mì Quảng có một vài điểm đặc trưng:\r\n\r\nGia vị tùy chỉnh: Khi ăn mì Quảng, bạn có thể thêm gia vị như tiêu, ớt tươi, hoặc nước mắm chua ngọt để tăng hương vị.\r\nĂn kèm với rau sống: Các loại rau sống như giá đỗ, húng quế, ngò gai không chỉ giúp tăng thêm hương vị mà còn giúp món ăn trở nên tươi mát, dễ ăn.\r\nĐậu phộng rang: Đậu phộng rang giã nhỏ là thành phần không thể thiếu khi thưởng thức mì Quảng. Vị bùi bùi của đậu phộng tạo nên sự hài hòa cho món ăn.</p>\r\n<p><b>6. Mì Quảng trong Văn Hóa Việt Nam</b>\r\nMì Quảng không chỉ là một món ăn mà còn là phần không thể thiếu trong ẩm thực của người dân miền Trung. Đây là món ăn gắn liền với đời sống thường ngày của người dân Quảng Nam và các tỉnh miền Trung. Mì Quảng là món ăn được ưa chuộng trong các bữa sáng tại các quán ăn ven đường hoặc trong các bữa tiệc gia đình.\r\n\r\nNgoài ra, mì Quảng cũng đã được biết đến và yêu thích rộng rãi trong cả nước và quốc tế. Du khách đến Việt Nam thường không thể bỏ qua món mì Quảng như một phần không thể thiếu trong hành trình khám phá ẩm thực Việt.</p>', 50000),
(10, 'Cà ri', 'nước', 'images/cari.jpg', '<p><b>1. Nguồn Gốc của Cà Ri</b>\r\nCà Ri là món ăn có nguồn gốc từ Ấn Độ, nhưng khi du nhập vào Việt Nam, cà ri đã được người Việt biến tấu với các nguyên liệu và gia vị đặc trưng của đất nước. Món cà ri Việt Nam chịu ảnh hưởng mạnh mẽ từ nền ẩm thực của người Ấn Độ và Pháp, đặc biệt là vào thời kỳ Pháp thuộc. Tại Việt Nam, cà ri được chế biến theo nhiều kiểu khác nhau, với các nguyên liệu chủ yếu là thịt gà, bò, heo, hoặc hải sản, và không thể thiếu nước dừa tươi, tạo nên hương vị đặc trưng của món ăn.\r\n\r\nCà Ri không chỉ là món ăn phổ biến tại miền Nam Việt Nam mà còn xuất hiện rộng rãi ở miền Trung và miền Bắc, đặc biệt là trong các bữa tiệc hoặc dịp đặc biệt.</p>\r\n<hr>\r\n<p><b>2. Các Loại Cà Ri</b>\r\nCà Ri tại Việt Nam có rất nhiều biến thể tùy thuộc vào loại nguyên liệu và cách chế biến. Các loại cà ri phổ biến bao gồm:\r\n\r\n+ Cà Ri Gà: Đây là món cà ri phổ biến nhất ở Việt Nam, với thịt gà tươi, nấu cùng với các gia vị như nghệ, hành, tỏi, và nước dừa tươi, tạo ra món cà ri thơm ngon, béo ngậy.\r\n+ Cà Ri Bò: Món cà ri này thường sử dụng thịt bò, thường là thịt bắp bò hoặc thịt gân, được nấu mềm trong nước dùng dừa và các gia vị như nghệ, hạt điều, tạo ra hương vị đậm đà.\r\n+ Cà Ri Heo: Cà ri với thịt heo thường có vị béo ngậy và ngọt nhẹ, rất được ưa chuộng tại miền Tây Nam Bộ.\r\n+ Cà Ri Hải Sản: Cà ri với tôm, cá, mực hoặc các loại hải sản khác. Món ăn này có hương vị thanh nhẹ, thường được nấu với nước dừa và gia vị tươi, rất phù hợp trong các bữa ăn gia đình.\r\n+ Cà Ri Chay: Phiên bản không có thịt, chỉ có rau củ như khoai lang, khoai tây, cà rốt, đậu hũ và các loại nấm. Món cà ri này phù hợp cho người ăn chay hoặc muốn ăn một món ăn nhẹ nhàng, bổ dưỡng.</p>\r\n<hr>\r\n<p><b>3. Nguyên Liệu Chính của Cà Ri</b>\r\nĐể làm một nồi cà ri thơm ngon, bạn cần chuẩn bị các nguyên liệu cơ bản sau:\r\n\r\n+ Thịt (Gà, Bò, Heo, Hải sản): Tùy thuộc vào loại cà ri, bạn có thể chọn thịt gà, bò, heo hoặc các loại hải sản như tôm, mực, cá.\r\n+ Nước Dừa Tươi: Nước dừa tạo độ béo ngậy và hương vị thơm ngon đặc trưng cho món cà ri.\r\n+ Nghệ Tươi: Nghệ tươi là gia vị quan trọng, giúp tạo màu vàng đẹp mắt và hương vị đặc trưng cho cà ri.\r\n+ Cà Ri (Bột Cà Ri): Bột cà ri là một hỗn hợp gia vị đặc trưng, bao gồm các thành phần như nghệ, quế, đinh hương, tiêu, hạt điều, giúp tạo nên hương vị đậm đà.\r\n+ Khoai Lang, Khoai Tây, Cà Rốt: Các loại củ này giúp món cà ri thêm đậm đà và dễ ăn, cũng như giúp tạo độ sánh mịn cho nước dùng.\r\n+ Hành, Tỏi, Gừng: Các gia vị này không thể thiếu trong quá trình xào sơ thịt và tạo nền hương vị cho món cà ri.\r\n+ Gia Vị và Hương Liệu: Bao gồm nước mắm, đường, tiêu, và lá chanh hoặc lá cà ri (nếu có), giúp món ăn thêm phần đậm đà.</p>\r\n<hr>\r\n<p><b>4. Cách Chế Biến Cà Ri</b>\r\nCách chế biến cà ri Việt Nam gồm các bước cơ bản như sau:\r\n\r\n+ Sơ chế thịt: Thịt (gà, bò, heo, hải sản) được cắt miếng vừa ăn và ướp với gia vị cơ bản như muối, tiêu, hành, tỏi.\r\nXào gia vị: Nghệ tươi, tỏi, hành và gừng được xào thơm để tạo hương nền cho món ăn.\r\n+ Nấu thịt: Sau khi xào gia vị, thịt được cho vào nồi nấu cùng với nước dừa tươi, bột cà ri và các gia vị khác, đun sôi để thịt mềm.\r\n+ Thêm rau củ: Khoai lang, khoai tây và cà rốt được cho vào nồi cà ri và đun cho đến khi mềm.\r\n+ Chỉnh vị: Nêm nếm gia vị như nước mắm, đường, tiêu, ớt để cà ri có hương vị vừa ăn. Một số người thích thêm lá chanh hoặc lá cà ri để tạo hương thơm đặc biệt.\r\n+ Hoàn thành: Cà ri được hoàn thiện khi nước dùng sánh lại và thịt, rau củ đã thấm đều gia vị.</p>\r\n<hr>\r\n<p><b>5. Cách Ăn Cà Ri</b>\r\nCà Ri thường được ăn kèm với:\r\n\r\n+ Cơm Trắng: Cà ri rất hợp ăn với cơm trắng, đặc biệt là cơm nóng, giúp món ăn đậm đà hơn.\r\n+ Bánh Mì: Một số người thích ăn cà ri với bánh mì, giúp chấm nước cà ri thơm ngon.\r\n+ Bánh Bèo hoặc Bánh Xèo: Cà ri cũng có thể ăn kèm với các loại bánh như bánh bèo, bánh xèo, mang lại cảm giác mới lạ.\r\nKhi ăn cà ri, bạn có thể thêm gia vị như ớt tươi, tiêu, hoặc nước mắm để tạo vị cay, đậm đà theo sở thích cá nhân.</p>\r\n<hr>\r\n<p><b>6. Cà Ri trong Văn Hóa Việt Nam</b>\r\nCà Ri là món ăn phổ biến trong các bữa tiệc gia đình, đặc biệt là trong các dịp lễ tết, hoặc các bữa ăn sum họp. Món ăn này không chỉ có mặt tại các quán ăn, nhà hàng mà còn là món ăn đường phố được yêu thích.\r\n\r\nCà Ri mang đậm hương vị và là sự kết hợp của các yếu tố ẩm thực từ nhiều nền văn hóa, từ Ấn Độ đến Pháp, và được người Việt sáng tạo để phù hợp với khẩu vị địa phương. Đây là một món ăn dễ ăn, dễ chế biến, mang lại cảm giác ấm cúng trong những ngày lạnh hoặc trong các bữa ăn sum vầy.', 45000),
(11, 'Bún riêu', 'nước', 'images/bunrieu.jpeg', '<p><b>1. Nguồn Gốc của Bún Riêu</b>\r\nBún riêu là một món ăn truyền thống nổi tiếng của Việt Nam, có nguồn gốc từ miền Bắc, nhưng đã trở nên phổ biến trên khắp cả nước. Món bún riêu bắt nguồn từ những người dân nghèo, món ăn được chế biến đơn giản từ cua đồng, kết hợp với nước dùng thanh thanh và các nguyên liệu dễ tìm như bún, đậu hũ, thịt heo, hoặc các loại rau sống.\r\n\r\nDù có nguồn gốc từ miền Bắc, nhưng bún riêu cũng đã có mặt ở miền Trung và miền Nam, mỗi nơi có sự biến tấu khác nhau về nguyên liệu và cách chế biến. Ở miền Nam, bún riêu thường có thêm các loại gia vị, nước mắm, và hương vị có phần đậm đà hơn.</p>\r\n<hr>\r\n<p><b>2. Các Loại Bún Riêu</b>\r\nBún riêu tại Việt Nam có nhiều biến thể khác nhau tùy vào nguyên liệu sử dụng và cách chế biến. Một số loại bún riêu phổ biến là:\r\n\r\n+ Bún Riêu Cua: Đây là phiên bản truyền thống nhất, với nước dùng được nấu từ cua đồng xay nhuyễn và riêu cua đặc trưng. Món ăn có vị ngọt tự nhiên từ cua kết hợp với các loại gia vị như hành, tỏi, ớt.\r\n+ Bún Riêu Heo: Thay vì cua, bún riêu heo sử dụng nước dùng được nấu từ xương heo, kết hợp với riêu từ thịt heo hoặc thịt băm.\r\n+ Bún Riêu Bò: Bún riêu bò ít phổ biến hơn, nhưng cũng được chế biến với nước dùng từ xương bò, kết hợp với các nguyên liệu như thịt bò hoặc gân bò.\r\n+ Bún Riêu Chay: Phiên bản này không có thịt, thay vào đó là riêu từ đậu hũ, nấm, và các loại rau củ. Đây là lựa chọn phổ biến cho những người ăn chay hoặc muốn thưởng thức món ăn nhẹ nhàng hơn.\r\nBún Riêu Hải Sản: Sử dụng tôm, mực hoặc cá làm nguyên liệu chính, tạo nên món bún riêu có hương vị thanh nhẹ và phù hợp cho những người yêu thích hải sản.</p>\r\n<hr>\r\n<p><b>3. Nguyên Liệu Chính của Bún Riêu</b>\r\nCác nguyên liệu cơ bản để chế biến bún riêu bao gồm:\r\n\r\n+ Cua đồng (hoặc Xương Heo/Bò): Riêu cua là nguyên liệu chính của bún riêu, hoặc nếu không có cua, có thể thay thế bằng xương heo hoặc bò để nấu nước dùng.\r\n+ Đậu Hũ: Đậu hũ chiên giòn hoặc luộc là thành phần phổ biến trong bún riêu, tạo độ mềm mại và béo ngậy cho món ăn.\r\nBún: Bún tươi, thường là bún sợi nhỏ hoặc bún lá, là thành phần không thể thiếu của món ăn này.\r\n+ Cà Chua: Cà chua được bổ sung vào nước dùng để tạo vị chua tự nhiên, tăng thêm hương vị thanh mát cho món ăn.\r\nHành, Tỏi, Nghệ, Riêu: Các gia vị này được dùng để xào tạo hương nền cho món ăn.\r\n+ Gia Vị: Bao gồm nước mắm, muối, đường, tiêu, và ớt để nêm nếm cho phù hợp với khẩu vị.</p>\r\n<hr>\r\n<p><b>4. Cách Chế Biến Bún Riêu</b>\r\nQuy trình chế biến bún riêu bao gồm các bước cơ bản như sau:\r\n\r\n+ Sơ Chế Nguyên Liệu: Cua đồng được rửa sạch, sau đó giã nhuyễn hoặc xay nhuyễn. Xương heo hoặc bò được rửa sạch và ninh lấy nước dùng. Đậu hũ được cắt thành miếng vừa ăn, chiên giòn hoặc luộc.\r\n+ Nấu Nước Dùng: Xương heo (hoặc bò) được ninh trong nước cho đến khi ra vị ngọt. Nếu làm bún riêu cua, phần cua giã nhuyễn được cho vào nước dùng để tạo ra riêu cua.\r\n+ Xào Gia Vị: Hành, tỏi, nghệ được xào thơm để tạo nền hương vị cho nước dùng.\r\nNấu Nước Dùng: Nước dùng sẽ được cho thêm cà chua thái múi, gia vị và riêu cua để tạo ra hương vị đặc trưng. Để nước dùng được trong và đậm đà, người nấu sẽ vớt bọt thường xuyên.\r\n+ Hoàn Thành: Sau khi nước dùng đã sôi và hoàn thiện, bún được cho vào tô, thêm nước dùng, riêu cua, đậu hũ, và các nguyên liệu kèm theo. Cuối cùng, nêm nếm gia vị cho vừa ăn.</p>\r\n<hr>\r\n<p><b>5. Cách Ăn Bún Riêu</b>\r\nBún riêu thường được ăn kèm với:\r\n\r\n+ Rau sống: Các loại rau sống như rau thơm, giá đỗ, rau mùi, ngò gai... thường được ăn kèm để tăng độ tươi mát và làm món ăn thêm phần hấp dẫn.\r\n+ Chanh, ớt, và mắm tôm: Các gia vị như chanh, ớt tươi, hoặc mắm tôm là gia vị quen thuộc mà nhiều người thích thêm vào để tăng độ chua cay, đậm đà cho món bún riêu.\r\n+ Cơm trắng hoặc bánh mì: Đôi khi, người ta cũng ăn bún riêu kèm với cơm trắng hoặc bánh mì, đặc biệt trong những bữa ăn thịnh soạn.</p>\r\n<hr>\r\n<p><b>6. Bún Riêu trong Văn Hóa Việt Nam</b>\r\nBún riêu là món ăn đặc trưng trong ẩm thực Việt Nam, đặc biệt phổ biến trong các bữa sáng hoặc bữa trưa. Món ăn này rất được yêu thích trong các gia đình, bởi sự đơn giản, dễ chế biến và hương vị thanh nhẹ, dễ ăn. Bún riêu không chỉ xuất hiện trong các quán ăn mà còn là món ăn đường phố phổ biến, đặc biệt là ở các thành phố lớn.\r\n\r\nNgoài ra, bún riêu còn thường xuyên xuất hiện trong các dịp lễ tết hoặc các bữa ăn gia đình, nơi mà hương vị của món ăn hòa quyện cùng không khí quây quần bên người thân. Món ăn này còn thể hiện sự sáng tạo của người Việt khi kết hợp các nguyên liệu dễ tìm nhưng vẫn đảm bảo hương vị thơm ngon, hấp dẫn.</p>', 30000);
INSERT INTO `dishes` (`id`, `name`, `category`, `image`, `description`, `price`) VALUES
(12, 'Bánh xèo', 'khô', 'images/banhxeo.jpg', '<p><b>1. Nguồn Gốc của Bánh Xèo</b>\r\nBánh xèo là một món ăn đặc trưng của Việt Nam, có nguồn gốc từ miền Nam, nhưng đã trở thành món ăn phổ biến ở khắp các vùng miền. \"Bánh xèo\" có nghĩa là \"bánh phát ra tiếng kêu xèo xèo\" khi được đổ vào chảo nóng. Bánh xèo được làm từ bột gạo, nước cốt dừa và các nguyên liệu như tôm, thịt heo, giá đỗ, hành lá, tạo nên món ăn thơm ngon, giòn rụm và đậm đà hương vị.\r\n\r\nBánh xèo có sự ảnh hưởng từ các món ăn của người Khmer và người Chăm, nhưng qua thời gian, nó đã được người Việt sáng tạo và thay đổi để phù hợp với khẩu vị địa phương. Món bánh xèo phổ biến ở miền Nam, đặc biệt là trong các bữa ăn gia đình, tiệc tùng hay là món ăn đường phố yêu thích.</p>\r\n<hr>\r\n<p><b>2. Các Loại Bánh Xèo</b>\r\nBánh xèo ở Việt Nam có nhiều biến thể tùy vào nguyên liệu và cách chế biến. Một số loại bánh xèo phổ biến là:\r\n\r\n+ Bánh Xèo Miền Nam: Đây là phiên bản phổ biến nhất, bánh xèo miền Nam thường có kích thước lớn, nhân đầy đặn gồm tôm, thịt heo, giá đỗ, hành lá và đôi khi có thêm nấm. Vỏ bánh mỏng và giòn, khi ăn thường được cuốn với rau sống và chấm nước mắm pha.\r\n+ Bánh Xèo Miền Trung: Bánh xèo miền Trung có vỏ bánh mỏng hơn, thường được chiên với nhân đơn giản hơn nhưng vẫn giữ được độ giòn đặc trưng. Đặc biệt, ở một số vùng, bánh xèo còn được ăn với loại nước mắm pha đặc biệt.\r\n+ Bánh Xèo Chay: Phiên bản này thường có nhân là các loại rau củ như nấm, khoai lang, đậu hũ, hoặc các loại rau xanh. Đây là món ăn phù hợp cho những người ăn chay hoặc muốn thử một món ăn nhẹ nhàng.\r\n+ Bánh Xèo Tôm Cá: Phiên bản bánh xèo này thay thế thịt heo bằng tôm hoặc cá, tạo nên hương vị thanh mát và ngọt ngào từ hải sản.</p>\r\n<hr>\r\n<p><b>3. Nguyên Liệu Chính của Bánh Xèo</b>\r\nĐể làm món bánh xèo giòn rụm và thơm ngon, bạn cần chuẩn bị các nguyên liệu sau:\r\n\r\n+ Bột Gạo: Bột gạo là thành phần chính để làm vỏ bánh xèo. Bột này thường được pha với nước cốt dừa, giúp vỏ bánh mềm mại và giòn hơn.\r\n+ Nước Cốt Dừa: Nước cốt dừa giúp tạo độ béo ngậy cho vỏ bánh và làm bánh thêm thơm ngon.\r\n+ Tôm, Thịt Heo: Nhân bánh thường có tôm và thịt heo, được thái nhỏ và xào sơ với gia vị cho thơm.\r\n+ Giá Đỗ và Hành Lá: Các thành phần này được thêm vào nhân bánh để tạo độ giòn và vị thanh mát.\r\n+ Gia Vị: Bao gồm hành, tỏi, tiêu, nước mắm, và đường để xào nhân, làm cho bánh có hương vị đậm đà.\r\n+ Rau Sống: Các loại rau sống như lá xà lách, rau thơm, húng quế, và rau diếp cá thường được ăn kèm với bánh xèo, tạo độ tươi mát và cân bằng vị béo của bánh.</p>\r\n<hr>\r\n<p><b>4. Cách Chế Biến Bánh Xèo</b>\r\nQuy trình chế biến bánh xèo bao gồm các bước cơ bản như sau:\r\n\r\n+ Pha Bột: Bột gạo được pha với nước, nước cốt dừa và một chút muối để tạo thành hỗn hợp bột lỏng. Sau đó, bột sẽ được lọc qua rây để loại bỏ cặn bã và tạo độ mịn.\r\n+ Chuẩn Bị Nhân: Tôm và thịt heo được thái nhỏ, xào sơ với hành, tỏi, gia vị như tiêu, nước mắm để tạo hương vị. Giá đỗ và hành lá được chuẩn bị sẵn.\r\n+ Chiên Bánh: Chảo được làm nóng và cho dầu ăn vào. Khi dầu nóng, đổ một lớp bột mỏng vào chảo, sau đó thêm tôm, thịt, giá đỗ và hành lá lên trên. Bánh được chiên cho đến khi vỏ bánh vàng giòn, có tiếng xèo xèo đặc trưng.\r\n+ Hoàn Thành: Khi bánh chín, bánh được gấp lại và bày ra đĩa. Bánh xèo thường được ăn kèm với rau sống và chấm nước mắm pha chua ngọt.</p>\r\n<hr>\r\n<p><b>5. Cách Ăn Bánh Xèo</b>\r\nBánh xèo thường được ăn kèm với:\r\n\r\n+ Rau Sống: Rau xà lách, rau thơm, húng quế, diếp cá... giúp tăng độ tươi mát và cân bằng hương vị béo ngậy của bánh.\r\n+ Nước Mắm Chấm: Nước mắm chấm thường được pha với đường, giấm, ớt, tỏi và một chút nước lọc để tạo thành một loại nước chấm có vị mặn ngọt, cay và chua, giúp tăng hương vị cho bánh xèo.\r\n+ Cuốn Bánh: Một trong những cách ăn phổ biến là cuốn bánh xèo với rau sống và chấm nước mắm. Khi ăn, người ta thường cuộn bánh vào rau, chấm nước mắm rồi thưởng thức, mang lại cảm giác giòn ngon và đầy đủ hương vị.</p>\r\n<hr>\r\n<p><b>6. Bánh Xèo trong Văn Hóa Việt Nam</b>\r\nBánh xèo là món ăn mang đậm bản sắc văn hóa ẩm thực của Việt Nam, đặc biệt phổ biến trong các bữa ăn gia đình, tiệc tùng hoặc là món ăn đường phố. Món bánh này không chỉ nổi bật với sự kết hợp giữa bột gạo, nước cốt dừa và các nguyên liệu tươi ngon mà còn là biểu tượng của sự giao thoa giữa các nền ẩm thực.\r\n\r\nỞ miền Nam, bánh xèo là món ăn phổ biến trong các bữa tiệc, lễ hội và các dịp sum họp gia đình. Bánh xèo còn thể hiện sự sáng tạo trong ẩm thực Việt Nam, khi người Việt có thể biến tấu món ăn này theo khẩu vị và nguyên liệu có sẵn. Đặc biệt, bánh xèo còn mang ý nghĩa gắn kết cộng đồng, khi mọi người cùng ngồi quây quần và thưởng thức món ăn đơn giản nhưng đầy tình cảm.</p>', 35000);

